import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import ProgressRing from '../common/ProgressRing';
import { today, getLast7Days, formatDate, calcWaterGoal, pct } from '../../utils/helpers';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

const CUPS = [
  { label: 'Ngụm nhỏ', amount: 100, icon: '🥛', color: '#00d4ff' },
  { label: 'Ly nhỏ', amount: 150, icon: '🫗', color: '#00e5a0' },
  { label: 'Ly thường', amount: 250, icon: '🥤', color: '#a855f7' },
  { label: 'Chai nhỏ', amount: 330, icon: '🍶', color: '#ff7b35' },
  { label: 'Chai vừa', amount: 500, icon: '🍼', color: '#00d4ff' },
  { label: 'Chai lớn', amount: 750, icon: '💧', color: '#00e5a0' },
];

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload && payload.length) {
    return (
      <div style={{ background: '#161d2e', border: '1px solid rgba(0,229,160,0.2)', borderRadius: 10, padding: '8px 14px' }}>
        <div style={{ fontSize: 11, color: '#8892aa' }}>{label}</div>
        <div style={{ fontFamily: 'var(--font-display)', fontWeight: 700, color: '#00e5a0', fontSize: 16 }}>
          {payload[0].value}ml
        </div>
      </div>
    );
  }
  return null;
};

export default function WaterTracker() {
  const { state, dispatch } = useApp();
  const todayStr = today();
  const [customAmt, setCustomAmt] = useState('');
  const [lastAdded, setLastAdded] = useState(null);

  const latestWeight = state.weight.length > 0 ? state.weight[state.weight.length - 1].value : state.profile?.weight || 0;
  const GOAL = calcWaterGoal(latestWeight);

  const todayEntry = state.water.find(w => w.date === todayStr);
  const todayWater = todayEntry?.amount || 0;
  const todayLogs = todayEntry?.logs || [];

  const last7 = getLast7Days();
  const chartData = last7.map(d => ({
    date: formatDate(d),
    water: state.water.find(w => w.date === d)?.amount || 0,
  }));

  const handleAdd = (amount) => {
    dispatch({ type: 'ADD_WATER', payload: amount });
    setLastAdded(amount);
    setTimeout(() => setLastAdded(null), 2000);
  };

  const handleCustom = () => {
    if (!customAmt || isNaN(+customAmt) || +customAmt <= 0) return;
    handleAdd(+customAmt);
    setCustomAmt('');
  };

  const handleReset = () => {
    if (window.confirm('Đặt lại lượng nước hôm nay?')) dispatch({ type: 'RESET_WATER' });
  };

  const remaining = Math.max(0, GOAL - todayWater);
  const fillHeight = Math.min(100, pct(todayWater, GOAL));

  return (
    <div>
      <div style={styles.header}>
        <div>
          <div style={styles.title}>💧 Nước uống</div>
          <div style={styles.sub}>Theo dõi lượng nước nạp vào cơ thể</div>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={handleReset} style={{ color: '#ff4f8b', borderColor: 'rgba(255,79,139,0.2)' }}>
          🔄 Đặt lại
        </button>
      </div>

      {/* Hero section */}
      <div style={styles.heroSection}>
        {/* Bottle visual */}
        <div style={styles.bottleSection} className="card">
          <div style={styles.bottleName}>Mục tiêu: {GOAL}ml/ngày</div>

          {/* Water bottle SVG */}
          <div style={styles.bottleWrapper}>
            <svg width="90" height="200" viewBox="0 0 90 200">
              <defs>
                <clipPath id="bottleClip">
                  <path d="M25,20 L25,10 Q25,5 30,5 L60,5 Q65,5 65,10 L65,20 Q75,25 75,35 L75,185 Q75,195 65,195 L25,195 Q15,195 15,185 L15,35 Q15,25 25,20 Z" />
                </clipPath>
                <linearGradient id="waterGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#00e5a0" stopOpacity="0.9" />
                  <stop offset="100%" stopColor="#00a87a" stopOpacity="1" />
                </linearGradient>
              </defs>
              {/* Bottle outline */}
              <path
                d="M25,20 L25,10 Q25,5 30,5 L60,5 Q65,5 65,10 L65,20 Q75,25 75,35 L75,185 Q75,195 65,195 L25,195 Q15,195 15,185 L15,35 Q15,25 25,20 Z"
                fill="rgba(255,255,255,0.04)"
                stroke="rgba(0,229,160,0.3)"
                strokeWidth="1.5"
              />
              {/* Water fill */}
              <rect
                x="15" y={195 - (160 * fillHeight / 100)} width="60" height={160 * fillHeight / 100}
                fill="url(#waterGrad)"
                clipPath="url(#bottleClip)"
                style={{ transition: 'y 0.8s ease, height 0.8s ease' }}
              />
              {/* Shine */}
              <rect x="22" y="40" width="8" height="100" rx="4" fill="rgba(255,255,255,0.06)" clipPath="url(#bottleClip)" />
              {/* Markings */}
              {[25, 50, 75].map(p => (
                <line key={p} x1="65" y1={195 - (160 * p / 100)} x2="72" y2={195 - (160 * p / 100)} stroke="rgba(255,255,255,0.15)" strokeWidth="1" />
              ))}
            </svg>
          </div>

          <div style={styles.bottleStats}>
            <div style={styles.waterNum}>{todayWater}</div>
            <div style={styles.waterUnit}>ml uống được</div>
            <div style={styles.waterRemain}>còn {remaining}ml</div>
          </div>

          {lastAdded && (
            <div style={styles.lastAdded}>+{lastAdded}ml ✓</div>
          )}
        </div>

        {/* Progress + quick add */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 16 }}>
          {/* Progress ring */}
          <div className="card" style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
            <ProgressRing value={todayWater} goal={GOAL} size={90} color="#00e5a0" />
            <div>
              <div style={{ fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 15, color: '#f0f4ff' }}>Tiến độ hôm nay</div>
              <div style={{ fontSize: 13, color: '#8892aa', marginTop: 4 }}>{todayWater}ml / {GOAL}ml</div>
              <div style={{ fontSize: 12, color: pct(todayWater, GOAL) >= 100 ? '#00e5a0' : '#ff7b35', marginTop: 4, fontWeight: 600 }}>
                {pct(todayWater, GOAL) >= 100 ? '🎉 Đã đạt mục tiêu!' : `Cần thêm ${remaining}ml`}
              </div>
            </div>
          </div>

          {/* Quick add cups */}
          <div className="card" style={{ flex: 1 }}>
            <div style={styles.sectionTitle}>Thêm nhanh</div>
            <div style={styles.cupsGrid}>
              {CUPS.map(c => (
                <button key={c.amount} onClick={() => handleAdd(c.amount)} style={{ ...styles.cupBtn, borderColor: `${c.color}30` }}>
                  <span style={{ fontSize: 24 }}>{c.icon}</span>
                  <span style={{ fontFamily: 'var(--font-display)', fontWeight: 700, color: c.color, fontSize: 13 }}>{c.amount}ml</span>
                  <span style={{ fontSize: 10, color: '#8892aa' }}>{c.label}</span>
                </button>
              ))}
            </div>

            {/* Custom input */}
            <div style={styles.customRow}>
              <input
                type="number"
                className="input-field"
                placeholder="Lượng tùy chỉnh (ml)..."
                value={customAmt}
                onChange={e => setCustomAmt(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleCustom()}
                style={{ flex: 1 }}
              />
              <button className="btn btn-primary" onClick={handleCustom} disabled={!customAmt}>+ Thêm</button>
            </div>
          </div>
        </div>
      </div>

      {/* Log today */}
      {todayLogs.length > 0 && (
        <div className="card" style={{ margin: '20px 0' }}>
          <div style={styles.sectionTitle}>Nhật ký hôm nay ({todayLogs.length} lần)</div>
          <div style={styles.logList}>
            {[...todayLogs].reverse().slice(0, 8).map((log, i) => (
              <div key={i} style={styles.logItem}>
                <span style={{ fontSize: 16 }}>💧</span>
                <span style={{ fontFamily: 'var(--font-display)', fontWeight: 600, color: '#00e5a0' }}>+{log.amount}ml</span>
                <span style={{ fontSize: 12, color: '#8892aa', marginLeft: 'auto' }}>
                  {new Date(log.time).toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Weekly chart */}
      <div className="card">
        <div style={styles.sectionTitle}>Lượng nước 7 ngày qua</div>
        <ResponsiveContainer width="100%" height={180}>
          <BarChart data={chartData} barSize={16}>
            <XAxis dataKey="date" tick={{ fill: '#8892aa', fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis hide />
            <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(0,229,160,0.05)' }} />
            <Bar dataKey="water" fill="#00e5a0" radius={[4, 4, 0, 0]} fillOpacity={0.8} />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

const styles = {
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28 },
  title: { fontFamily: 'var(--font-display)', fontSize: 28, fontWeight: 800, color: '#f0f4ff', marginBottom: 4 },
  sub: { fontSize: 14, color: '#8892aa' },
  heroSection: { display: 'flex', gap: 20, marginBottom: 20, flexWrap: 'wrap' },
  bottleSection: { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12, minWidth: 180 },
  bottleName: { fontSize: 12, color: '#8892aa', textAlign: 'center' },
  bottleWrapper: { padding: '8px 0' },
  bottleStats: { textAlign: 'center' },
  waterNum: { fontFamily: 'var(--font-display)', fontSize: 32, fontWeight: 800, color: '#00e5a0' },
  waterUnit: { fontSize: 12, color: '#8892aa' },
  waterRemain: { fontSize: 12, color: '#ff7b35', marginTop: 4 },
  lastAdded: {
    padding: '6px 16px',
    background: 'rgba(0,229,160,0.15)',
    border: '1px solid rgba(0,229,160,0.3)',
    borderRadius: 20,
    fontSize: 13,
    fontWeight: 700,
    fontFamily: 'var(--font-display)',
    color: '#00e5a0',
    animation: 'fadeInUp 0.3s ease',
  },
  sectionTitle: { fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 15, color: '#f0f4ff', marginBottom: 14 },
  cupsGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 8, marginBottom: 14 },
  cupBtn: {
    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4,
    padding: '12px 8px', borderRadius: 12, background: 'rgba(255,255,255,0.02)',
    border: '1px solid rgba(255,255,255,0.06)', cursor: 'pointer', transition: 'all 0.2s ease',
  },
  customRow: { display: 'flex', gap: 10 },
  logList: { display: 'flex', flexDirection: 'column', gap: 8 },
  logItem: {
    display: 'flex', alignItems: 'center', gap: 10,
    padding: '8px 12px',
    background: 'rgba(0,229,160,0.04)',
    borderRadius: 8,
    border: '1px solid rgba(0,229,160,0.08)',
  },
};
